const input = $json;

// Modo compatibilidade máxima para n8n 2.13 (create workflow)
// Mantém somente chaves essenciais para reduzir falhas de validação.
const allowedNodeKeys = new Set([
  'name',
  'type',
  'typeVersion',
  'position',
  'parameters',
  'disabled'
]);

const cleanNode = (node) => {
  const cleaned = {};
  for (const key of Object.keys(node || {})) {
    if (allowedNodeKeys.has(key)) cleaned[key] = node[key];
  }
  return cleaned;
};

const cleanedNodes = Array.isArray(input.nodes) ? input.nodes.map(cleanNode) : [];

return {
  sourceWorkflowId: input.id || null,
  sourceWorkflowName: input.name || 'sem_nome',
  workflowObject: {
    name: input.name || 'Workflow sem nome',
    nodes: cleanedNodes,
    connections: input.connections || {},
    settings: {
      executionOrder: 'v1'
    }
  }
};

const out = [];

function safeStringify(v) {
  try {
    return JSON.stringify(v);
  } catch {
    return String(v);
  }
}

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return null;
}

for (let i = 0; i < items.length; i++) {
  const item = items[i] || {};
  const j = item.json || {};

  let pairedIndex = i;
  if (typeof item.pairedItem === 'object' && item.pairedItem !== null && Number.isInteger(item.pairedItem.item)) {
    pairedIndex = item.pairedItem.item;
  }

  let source = {};
  try {
    const prev = $items('Sanitize Payload', 0, pairedIndex);
    if (Array.isArray(prev) && prev[0] && prev[0].json) source = prev[0].json;
    else if (prev && prev.json) source = prev.json;
  } catch {}

  const srcName = pickFirst(
    j.sourceWorkflowName,
    source.sourceWorkflowName,
    j.workflowObject?.name,
    source.workflowObject?.name,
    j.name,
    'desconhecido'
  );

  const srcId = pickFirst(
    j.sourceWorkflowId,
    source.sourceWorkflowId,
    null
  );

  const errObj = pickFirst(
    j.error,
    item.error,
    j.data?.error,
    j.response?.error,
    j.cause,
    null
  );

  const hasError = !!(
    errObj ||
    j.httpCode >= 400 ||
    j.statusCode >= 400 ||
    j.code ||
    j.message?.toLowerCase?.().includes('error')
  );

  if (hasError) {
    const msg = pickFirst(
      errObj?.message,
      errObj?.description,
      errObj?.error,
      j.errorMessage,
      j.message,
      j.description,
      j.response?.message,
      j.response?.data?.message,
      j.data?.message,
      errObj ? safeStringify(errObj) : null,
      safeStringify(j),
      'Erro nao detalhado'
    );

    const code = pickFirst(
      errObj?.httpCode,
      errObj?.statusCode,
      errObj?.code,
      j.httpCode,
      j.statusCode,
      j.code,
      null
    );

    out.push({
      status: 'erro',
      sourceWorkflowId: srcId,
      sourceWorkflowName: srcName,
      targetWorkflowId: null,
      targetWorkflowName: null,
      errorCode: code,
      errorMessage: String(msg)
    });
  } else {
    out.push({
      status: 'sucesso',
      sourceWorkflowId: srcId,
      sourceWorkflowName: srcName,
      targetWorkflowId: j.id || null,
      targetWorkflowName: j.name || j.workflowObject?.name || null,
      errorCode: null,
      errorMessage: null
    });
  }
}

return out.map((json) => ({ json }));

const rows = items.map(i => i.json);
const success = rows.filter(r => r.status === 'sucesso');
const failed = rows.filter(r => r.status === 'erro');

const report = {
  executionAt: new Date().toISOString(),
  total: rows.length,
  success: success.length,
  failed: failed.length,
  successRate: rows.length ? Number(((success.length / rows.length) * 100).toFixed(2)) : 0,
  failedItems: failed.map(f => ({
    sourceWorkflowId: f.sourceWorkflowId,
    sourceWorkflowName: f.sourceWorkflowName,
    errorCode: f.errorCode,
    errorMessage: f.errorMessage
  })),
  createdItems: success.map(s => ({
    sourceWorkflowId: s.sourceWorkflowId,
    sourceWorkflowName: s.sourceWorkflowName,
    targetWorkflowId: s.targetWorkflowId,
    targetWorkflowName: s.targetWorkflowName
  }))
};

const markdown = [
  '# Relatorio de Importacao sem Substituicao',
  '',
  `- Data/Hora: ${report.executionAt}`,
  `- Total processado: ${report.total}`,
  `- Sucessos: ${report.success}`,
  `- Falhas: ${report.failed}`,
  `- Taxa de sucesso: ${report.successRate}%`,
  '',
  '## Falhas',
  ...(report.failedItems.length
    ? report.failedItems.map(f => `- ${f.sourceWorkflowName} (${f.sourceWorkflowId || 'sem_id'}): [${f.errorCode || 'sem_codigo'}] ${f.errorMessage}`)
    : ['- Nenhuma falha'])
].join('\n');

return [{ json: { report, markdown, details: rows } }];
